      if (r.ok) {
        toast({ title: "Demo data restored", description: "All demo data is back and ready for your presentation!" });
        setDone(true);
      } else {
        toast({ title: "Error", description: data.error, variant: "destructive" });
      }
    } catch {
      toast({ title: "Error", description: "Request failed", variant: "destructive" });
    } finally {
      setRestoring(false);
    }
  }

