import { useState, useEffect } from "react";
import { RequireAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";
import { Settings, Phone, Save, Info, CheckCircle2 } from "lucide-react";

function AdminSettingsContent() {
  const { toast } = useToast();
  const [settings, setSettings] = useState<Record<string, string>>({});
  const [alertPhone, setAlertPhone] = useState("");
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    fetch("/api/admin/settings", { credentials: "include" })
      .then(r => r.ok ? r.json() : {})
      .then((data: Record<string, string>) => {
        setSettings(data);
        setAlertPhone(data["alert_redirect_phone"] ?? "");
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  async function saveSettings() {
    setSaving(true);
    try {
      const r = await fetch("/api/admin/settings", {
        method: "PUT",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ alert_redirect_phone: alertPhone.trim() }),
      });
      if (!r.ok) throw new Error("Failed to save");
      const data = await r.json();
      setSettings(data);
      toast({ title: "Settings saved", description: "Alert redirect phone updated successfully." });
    } catch {
      toast({ title: "Error", description: "Could not save settings.", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  }

  return (
    <div className="min-h-screen">
      <div className="page-header-admin px-8 pt-8 pb-14">
        <div className="max-w-7xl mx-auto">
          <h1 className="text-3xl font-bold text-white mb-1 flex items-center gap-2">
            <Settings size={26} /> System Settings
          </h1>
          <p className="text-violet-200/70 text-sm">Configure global system behaviour for all portals</p>
        </div>
      </div>

      <div className="max-w-3xl mx-auto px-8 -mt-6 pb-10 space-y-6">
        {/* Alert phone redirect */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
          <div className="flex items-center gap-2 mb-1">
            <Phone size={16} className="text-violet-600" />
            <h2 className="font-bold text-gray-900">Alert Redirect Phone</h2>
          </div>
          <p className="text-xs text-gray-400 mb-5">
            When set, all voice calls and WhatsApp alerts from the Faculty Alert Center will be pre-filled with this number instead of each student's/parent's actual phone. The faculty can still edit the number before sending.
          </p>

          <div className="bg-violet-50 border border-violet-100 rounded-xl p-4 mb-5 flex gap-3">
            <Info size={15} className="text-violet-500 flex-shrink-0 mt-0.5" />
            <div className="text-xs text-violet-700 leading-relaxed">
              <strong>Why use this?</strong> During demos or testing, set this to your own number so all Twilio alerts go to you regardless of which student is selected. After the demo, clear it to restore per-student phone numbers.
              <br /><br />
              <strong>Format:</strong> Indian numbers without +91 (e.g. <code className="bg-violet-100 px-1 rounded">9380838591</code>) or with country code (e.g. <code className="bg-violet-100 px-1 rounded">+919380838591</code>).
            </div>
          </div>

          {loading ? (
            <div className="h-10 bg-gray-100 rounded-xl animate-pulse" />
          ) : (
            <div className="flex gap-3">
              <Input
                value={alertPhone}
                onChange={e => setAlertPhone(e.target.value)}
                placeholder="e.g. 9380838591  (leave blank to use per-student phones)"
                className="flex-1 font-mono text-sm"
              />
              <Button
                onClick={saveSettings}
                disabled={saving}
                className="bg-violet-700 hover:bg-violet-800 text-white gap-2 flex-shrink-0"
              >
                {saving ? (
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <Save size={14} />
                )}
                Save
              </Button>
            </div>
          )}

          {settings["alert_redirect_phone"] && (
            <div className="flex items-center gap-2 mt-3 text-xs text-emerald-600">
              <CheckCircle2 size={13} />
              Currently redirecting all alerts to: <code className="bg-emerald-50 px-2 py-0.5 rounded font-mono">{settings["alert_redirect_phone"]}</code>
            </div>
          )}
          {!loading && !settings["alert_redirect_phone"] && (
            <p className="text-xs text-gray-400 mt-3">No redirect set — Alert Center uses each student's/parent's own phone number.</p>
          )}
        </div>

        {/* Info box */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
          <h2 className="font-bold text-gray-900 mb-3 text-sm">How to Change Data After Publishing</h2>
          <div className="space-y-3 text-xs text-gray-600 leading-relaxed">
            <div className="flex gap-2.5">
              <div className="w-5 h-5 rounded-full bg-violet-100 text-violet-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0 mt-0.5">1</div>
              <div><strong className="text-gray-800">User Management</strong> — Go to <a href="/guardian-admin/users" className="text-violet-600 underline">/guardian-admin/users</a> to edit names, emails, phones, sections, semesters, and reset passwords for any user without touching the database.</div>
            </div>
            <div className="flex gap-2.5">
              <div className="w-5 h-5 rounded-full bg-violet-100 text-violet-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0 mt-0.5">2</div>
              <div><strong className="text-gray-800">Reset Demo Data</strong> — Go to <a href="/guardian-admin/demo" className="text-violet-600 underline">/guardian-admin/demo</a> and click "Restore Demo Data" to re-seed everything from scratch.</div>
            </div>
            <div className="flex gap-2.5">
              <div className="w-5 h-5 rounded-full bg-violet-100 text-violet-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0 mt-0.5">3</div>
              <div><strong className="text-gray-800">Direct DB (advanced)</strong> — On Replit, go to your project → Tools → Database → Query. Run SQL directly: <code className="bg-gray-100 px-1 rounded">UPDATE profiles SET phone='...' WHERE email='...'</code>. For the production DB after publishing, use the Replit deployment panel → Database tab.</div>
            </div>
            <div className="flex gap-2.5">
              <div className="w-5 h-5 rounded-full bg-violet-100 text-violet-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0 mt-0.5">4</div>
              <div><strong className="text-gray-800">Schema changes</strong> — Edit <code className="bg-gray-100 px-1 rounded">lib/db/src/schema/</code> files in Replit, then run <code className="bg-gray-100 px-1 rounded">pnpm --filter @workspace/db run push</code> in the Shell to apply. For production, run the same command with <code className="bg-gray-100 px-1 rounded">DATABASE_URL</code> set to the production connection string.</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function AdminSettings() {
