  );
}

import { useState, useRef, useEffect } from "react";
import { RequireAuth, useAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Send, MessageSquare, User, Wifi, Trash2 } from "lucide-react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";

interface Conversation {
  partnerId: number;
  partnerName: string;
  partnerRole: string;
  studentInfo: { name: string; usn: string } | null;
  lastMessage: string | null;
  lastTime: string | null;
  lastSenderId: number | null;
}

interface ChatMessage {
  id: number;
  senderId: number;
  receiverId: number;
  message: string;
  createdAt: string;
}

async function fetchConversations(): Promise<Conversation[]> {
  const r = await fetch("/api/proctor-messages/conversations", { credentials: "include" });
  if (!r.ok) throw new Error("Failed to fetch conversations");
  return r.json();
}

async function fetchMessages(withUserId: number): Promise<ChatMessage[]> {
  const r = await fetch(`/api/proctor-messages?withUserId=${withUserId}`, { credentials: "include" });
  if (!r.ok) throw new Error("Failed to fetch messages");
  return r.json();
}

async function sendMessage(receiverId: number, message: string) {
  const r = await fetch("/api/proctor-messages", {
    method: "POST",
    credentials: "include",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ data: { receiverId, message } }),
  });
  if (!r.ok) throw new Error("Failed to send");
  return r.json();
}

async function deleteMessage(id: number) {
  const r = await fetch(`/api/proctor-messages/${id}`, { method: "DELETE", credentials: "include" });
  if (!r.ok) throw new Error("Failed to delete");
  return r.json();
}

function ChatContent() {
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [selectedPartnerId, setSelectedPartnerId] = useState<number | null>(null);
  const [message, setMessage] = useState("");
  const [hoveredMsgId, setHoveredMsgId] = useState<number | null>(null);
  const bottomRef = useRef<HTMLDivElement>(null);

  const { data: conversations = [], isLoading: loadingConvs } = useQuery({
    queryKey: ["faculty-conversations"],
    queryFn: fetchConversations,
    refetchInterval: 5000,
  });

  const selectedConv = conversations.find((c) => c.partnerId === selectedPartnerId);

  const { data: messages = [], isLoading: loadingMsgs } = useQuery({
    queryKey: ["faculty-messages", selectedPartnerId],
    queryFn: () => fetchMessages(selectedPartnerId!),
    enabled: selectedPartnerId !== null,
    refetchInterval: 3000,
  });

  const { mutate: doSend, isPending } = useMutation({
    mutationFn: ({ receiverId, msg }: { receiverId: number; msg: string }) =>
      sendMessage(receiverId, msg),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["faculty-messages", selectedPartnerId] });
      queryClient.invalidateQueries({ queryKey: ["faculty-conversations"] });
      setMessage("");
    },
  });

  const { mutate: doDelete } = useMutation({
    mutationFn: (id: number) => deleteMessage(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["faculty-messages", selectedPartnerId] });
      queryClient.invalidateQueries({ queryKey: ["faculty-conversations"] });
    },
    onError: () => {
      toast({ title: "Could not delete", description: "Message may have already been removed.", variant: "destructive" });
    },
  });

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  useEffect(() => {
    if (conversations.length > 0 && selectedPartnerId === null) {
      setSelectedPartnerId(conversations[0]!.partnerId);
    }
  }, [conversations, selectedPartnerId]);

  function handleSend(e: React.FormEvent) {
    e.preventDefault();
    if (!message.trim() || selectedPartnerId === null) return;
    doSend({ receiverId: selectedPartnerId, msg: message.trim() });
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      if (message.trim() && selectedPartnerId !== null) {
        doSend({ receiverId: selectedPartnerId, msg: message.trim() });
      }
    }
  }

  return (
    <div className="min-h-screen">
      <div className="page-header-faculty px-8 pt-8 pb-14">
        <div className="max-w-6xl mx-auto">
          <p className="text-rose-300 text-xs font-semibold uppercase tracking-wider mb-2">Parent Communication</p>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <MessageSquare size={22} /> Proctor Chat
          </h1>
          <p className="text-rose-200/70 text-sm mt-1">Secure messaging with parents of your assigned students</p>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-8 -mt-6 pb-10">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden flex" style={{ height: "74vh" }}>
          {/* Left: Conversation list */}
          <div className="w-72 border-r border-gray-100 flex flex-col flex-shrink-0">
            <div className="px-4 py-3.5 border-b border-gray-50">
              <div className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Parent Conversations</div>
              <div className="flex items-center gap-1.5 mt-1">
                <div className="w-1.5 h-1.5 rounded-full bg-rose-400 animate-pulse" />
                <span className="text-[10px] text-gray-300">Live — updates every 5s</span>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto">
              {loadingConvs ? (
                <div className="p-4 space-y-3">
                  {[1, 2, 3].map((i) => (
                    <div key={i} className="flex gap-3 items-center animate-pulse">
                      <div className="w-9 h-9 rounded-full bg-gray-100 flex-shrink-0" />
                      <div className="flex-1">
                        <div className="h-3 bg-gray-100 rounded w-2/3 mb-1" />
                        <div className="h-2.5 bg-gray-50 rounded w-full" />
                      </div>
                    </div>
                  ))}
                </div>
              ) : conversations.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-center p-6">
                  <MessageSquare size={28} className="text-gray-200 mb-3" />
                  <p className="text-xs text-gray-300">No parent conversations yet</p>
                  <p className="text-[10px] text-gray-200 mt-1">Conversations appear when parents message you</p>
                </div>
              ) : (
                conversations.map((conv) => {
                  const isSelected = conv.partnerId === selectedPartnerId;
                  const isMyLast = conv.lastSenderId === user?.id;
                  return (
                    <button
                      key={conv.partnerId}
                      onClick={() => setSelectedPartnerId(conv.partnerId)}
                      className={`w-full text-left px-4 py-3.5 flex items-start gap-3 hover:bg-gray-50 transition-colors border-b border-gray-50 ${isSelected ? "bg-rose-50 border-l-2 border-l-rose-600" : ""}`}
                    >
                      <div className={`w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0 ${isSelected ? "bg-rose-100 text-rose-700" : "bg-gray-100 text-gray-500"}`}>
                        {conv.partnerName.charAt(0)}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between gap-1">
                          <span className={`text-sm font-semibold truncate ${isSelected ? "text-rose-900" : "text-gray-800"}`}>
                            {conv.partnerName}
                          </span>
                          {conv.lastTime && (
                            <span className="text-[9px] text-gray-300 flex-shrink-0">
                              {new Date(conv.lastTime).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
                            </span>
                          )}
                        </div>
                        {conv.studentInfo && (
                          <div className="text-[10px] text-rose-500 font-medium truncate">
                            Parent of {conv.studentInfo.name}
                          </div>
                        )}
                        {conv.lastMessage && (
                          <div className="text-xs text-gray-400 truncate mt-0.5">
                            {isMyLast ? "You: " : ""}{conv.lastMessage}
                          </div>
                        )}
                        {!conv.lastMessage && (
                          <div className="text-xs text-gray-300 italic">No messages yet — say hello!</div>
                        )}
                      </div>
                    </button>
                  );
                })
              )}
            </div>
          </div>

          {/* Right: Message thread */}
          <div className="flex-1 flex flex-col">
            {selectedPartnerId === null ? (
              <div className="flex-1 flex flex-col items-center justify-center text-center">
                <div className="w-16 h-16 rounded-2xl bg-rose-50 flex items-center justify-center mb-4">
                  <MessageSquare size={28} className="text-rose-300" />
                </div>
                <p className="font-semibold text-gray-400 text-sm">Select a conversation</p>
                <p className="text-gray-300 text-xs mt-1">Pick a parent from the left to start messaging</p>
              </div>
            ) : (
              <>
                {/* Thread header */}
                <div className="px-5 py-4 border-b border-gray-50 flex items-center gap-3">
                  <div className="w-9 h-9 rounded-xl bg-rose-100 flex items-center justify-center font-bold text-rose-700 text-sm">
                    {selectedConv?.partnerName.charAt(0) ?? "?"}
                  </div>
                  <div className="flex-1">
                    <div className="font-bold text-gray-900 text-sm">{selectedConv?.partnerName ?? "Parent"}</div>
                    {selectedConv?.studentInfo && (
                      <div className="text-xs text-gray-400">
                        Parent of {selectedConv.studentInfo.name} · {selectedConv.studentInfo.usn}
                      </div>
                    )}
                  </div>
                  <div className="flex items-center gap-1.5 text-xs text-rose-600 bg-rose-50 px-3 py-1.5 rounded-full">
                    <Wifi size={11} />
                    <span>Live Chat</span>
                  </div>
                </div>

                {/* Messages */}
                <div className="flex-1 overflow-y-auto p-5 space-y-2 bg-gray-50/30">
                  {loadingMsgs ? (
                    <div className="flex items-center justify-center h-full">
                      <div className="animate-spin w-6 h-6 border-2 border-rose-200 border-t-rose-600 rounded-full" />
                    </div>
                  ) : messages.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-center">
                      <MessageSquare size={28} className="text-gray-200 mb-3" />
                      <p className="text-sm text-gray-400">No messages yet</p>
                      <p className="text-xs text-gray-300 mt-1">Send a message to start the conversation</p>
                    </div>
                  ) : (
                    messages.map((msg) => {
                      const isMine = msg.senderId === user?.id;
                      return (
                        <div
                          key={msg.id}
                          className={`flex items-end gap-2 group ${isMine ? "justify-end" : "justify-start"}`}
                          onMouseEnter={() => setHoveredMsgId(msg.id)}
                          onMouseLeave={() => setHoveredMsgId(null)}
                        >
                          {!isMine && (
                            <div className="w-7 h-7 rounded-full bg-gray-100 flex items-center justify-center flex-shrink-0 mb-4">
                              <User size={12} className="text-gray-400" />
                            </div>
                          )}
                          <div className={`flex flex-col max-w-sm ${isMine ? "items-end" : "items-start"}`}>
                            <div className={`flex items-end gap-1.5 ${isMine ? "flex-row-reverse" : "flex-row"}`}>
                              <div className={`px-4 py-2.5 rounded-2xl text-sm ${isMine ? "bg-rose-900 text-white rounded-br-sm" : "bg-white text-gray-800 rounded-bl-sm border border-gray-100"}`}>
                                {msg.message}
                              </div>
                              {isMine && hoveredMsgId === msg.id && (
                                <button
                                  onClick={() => doDelete(msg.id)}
                                  className="w-6 h-6 rounded-full bg-gray-100 hover:bg-red-100 flex items-center justify-center transition-colors mb-1 flex-shrink-0"
                                  title="Delete message"
                                >
                                  <Trash2 size={11} className="text-gray-400 hover:text-red-500" />
                                </button>
                              )}
                            </div>
                            <span className="text-[10px] text-gray-300 mt-1 px-1">
                              {new Date(msg.createdAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
                            </span>
                          </div>
                          {isMine && (
                            <div className="w-7 h-7 rounded-full bg-rose-900 flex items-center justify-center text-white text-xs font-bold flex-shrink-0 mb-4">
                              {user?.name?.charAt(0) ?? "F"}
                            </div>
                          )}
                        </div>
                      );
                    })
                  )}
                  <div ref={bottomRef} />
                </div>

                {/* Input */}
                <div className="border-t border-gray-100 bg-white p-4">
                  <form onSubmit={handleSend} className="flex gap-2">
                    <Input
                      value={message}
                      onChange={(e) => setMessage(e.target.value)}
                      onKeyDown={handleKeyDown}
                      placeholder="Type a message… (Enter to send)"
                      className="flex-1 bg-gray-50 border-gray-100 rounded-xl text-sm"
                      autoComplete="off"
                    />
                    <Button
                      type="submit"
                      className="bg-rose-900 hover:bg-rose-800 rounded-xl w-11 h-10 p-0"
                      disabled={isPending || !message.trim()}
                    >
                      {isPending ? (
                        <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      ) : (
                        <Send size={15} />
                      )}
                    </Button>
                  </form>
                  <p className="text-[10px] text-gray-300 mt-2 text-center">Hover over your own messages to delete them</p>
                </div>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default function FacultyChat() {
  return (
    <RequireAuth allowedRoles={["faculty"]}>
