}

async function deleteMessage(id: number) {
  const r = await fetch(`/api/proctor-messages/${id}`, { method: "DELETE", credentials: "include" });
  if (!r.ok) throw new Error("Failed to delete");
  return r.json();
}

function ChatContent() {
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [message, setMessage] = useState("");
  const [hoveredMsgId, setHoveredMsgId] = useState<number | null>(null);
  const bottomRef = useRef<HTMLDivElement>(null);

  const { data: conversations = [] } = useQuery({
    queryKey: ["parent-conversations"],
    queryFn: fetchConversations,
    refetchInterval: 5000,
  });

  const proctor = conversations[0] ?? null;
  const proctorId = proctor?.partnerId ?? null;

  const { data: messages = [], isLoading } = useQuery({
    queryKey: ["parent-messages", proctorId],
    queryFn: () => fetchMessages(proctorId!),
    enabled: proctorId !== null,
    refetchInterval: 3000,
  });

  const { mutate: doSend, isPending } = useMutation({
    mutationFn: ({ receiverId, msg }: { receiverId: number; msg: string }) =>
      sendMessage(receiverId, msg),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["parent-messages", proctorId] });
      queryClient.invalidateQueries({ queryKey: ["parent-conversations"] });
      setMessage("");
    },
  });

  const { mutate: doDelete } = useMutation({
    mutationFn: (id: number) => deleteMessage(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["parent-messages", proctorId] });
      queryClient.invalidateQueries({ queryKey: ["parent-conversations"] });
    },
    onError: () => {
      toast({ title: "Could not delete", description: "Message may have already been removed.", variant: "destructive" });
    },
  });

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  function handleSend(e: React.FormEvent) {
    e.preventDefault();
    if (!message.trim() || proctorId === null) return;
    doSend({ receiverId: proctorId, msg: message.trim() });
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      if (message.trim() && proctorId !== null) {
        doSend({ receiverId: proctorId, msg: message.trim() });
      }
    }
  }

  const groupedMessages = messages.reduce<Record<string, ChatMessage[]>>((acc, msg) => {
    const day = new Date(msg.createdAt).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" });
    if (!acc[day]) acc[day] = [];
    acc[day]!.push(msg);
    return acc;
  }, {});

  return (
    <div className="min-h-screen">
      <div className="page-header-parent px-8 pt-8 pb-14">
        <div className="max-w-4xl mx-auto">
          <p className="text-emerald-300 text-xs font-semibold uppercase tracking-wider mb-2">Secure Messaging</p>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <MessageSquare size={22} /> Proctor Chat
          </h1>
          <p className="text-emerald-200/70 text-sm mt-1">Direct channel with your child's assigned mentor</p>
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-8 -mt-6 pb-10">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden flex flex-col" style={{ height: "72vh" }}>
          {/* Chat header */}
          <div className="px-5 py-4 border-b border-gray-50 flex items-center gap-3 bg-white">
            <div className="w-10 h-10 bg-emerald-100 rounded-xl flex items-center justify-center font-bold text-emerald-700 text-sm flex-shrink-0">
              {proctor ? proctor.partnerName.charAt(0) : "?"}
            </div>
            <div className="flex-1">
              <div className="font-bold text-gray-900 text-sm">
                {proctor ? proctor.partnerName : "Proctor / Mentor Faculty"}
              </div>
              {proctor?.studentInfo && (
                <div className="text-xs text-gray-400">
                  Proctor of {proctor.studentInfo.name}
                  {proctor.studentInfo.usn ? ` · ${proctor.studentInfo.usn}` : ""}
                </div>
              )}
              {!proctor && (
                <div className="text-xs text-gray-400">No proctor assigned yet — contact administration</div>
              )}
              {proctor && (
                <div className="flex items-center gap-1.5 text-xs text-gray-400 mt-0.5">
                  <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
                  Live — updates every 3 seconds
                </div>
              )}
            </div>
            {proctor && (
              <div className="flex items-center gap-1.5 text-xs text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-full">
                <Wifi size={11} />
                <span>Live Chat</span>
              </div>
            )}
          </div>

          {/* Messages area */}
          <div className="flex-1 overflow-y-auto p-5 space-y-4 bg-gray-50/30">
            {proctorId === null ? (
              <div className="flex flex-col items-center justify-center h-full text-center">
                <div className="w-16 h-16 rounded-2xl bg-emerald-50 flex items-center justify-center mb-4">
                  <MessageSquare size={28} className="text-emerald-400" />
                </div>
                <p className="font-semibold text-gray-400 text-sm">No proctor assigned</p>
                <p className="text-gray-300 text-xs mt-1">
                  Your child has not been assigned a proctor yet. Please contact the administration.
                </p>
              </div>
            ) : isLoading ? (
              <div className="flex flex-col items-center justify-center h-full gap-3 text-gray-300">
                <div className="animate-spin w-6 h-6 border-2 border-emerald-200 border-t-emerald-600 rounded-full" />
                <p className="text-sm">Loading messages…</p>
              </div>
            ) : Object.keys(groupedMessages).length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-center">
                <div className="w-16 h-16 rounded-2xl bg-emerald-50 flex items-center justify-center mb-4">
                  <MessageSquare size={28} className="text-emerald-400" />
                </div>
                <p className="font-semibold text-gray-400 text-sm">No messages yet</p>
                <p className="text-gray-300 text-xs mt-1">Start a conversation with your child's proctor</p>
              </div>
            ) : (
              Object.entries(groupedMessages).map(([day, dayMessages]) => (
                <div key={day}>
                  <div className="flex items-center gap-3 my-4">
                    <div className="flex-1 h-px bg-gray-100" />
                    <span className="text-[10px] font-semibold text-gray-300 uppercase tracking-wider px-2">{day}</span>
                    <div className="flex-1 h-px bg-gray-100" />
                  </div>

                  <div className="space-y-2">
                    {dayMessages.map((msg) => {
                      const isMine = msg.senderId === user?.id;
                      return (
                        <div
                          key={msg.id}
                          className={`flex items-end gap-2 group ${isMine ? "justify-end" : "justify-start"}`}
                          onMouseEnter={() => setHoveredMsgId(msg.id)}
                          onMouseLeave={() => setHoveredMsgId(null)}
                        >
                          {!isMine && (
                            <div className="w-7 h-7 rounded-full bg-emerald-100 flex items-center justify-center text-emerald-700 text-xs font-bold flex-shrink-0 mb-1">
                              <User size={12} />
                            </div>
                          )}
                          <div className={`max-w-sm ${isMine ? "items-end" : "items-start"} flex flex-col`}>
                            <div className={`flex items-end gap-1.5 ${isMine ? "flex-row-reverse" : "flex-row"}`}>
                              <div className={`px-4 py-2.5 rounded-2xl text-sm leading-relaxed ${
                                isMine
                                  ? "bg-emerald-800 text-white rounded-br-sm shadow-sm"
                                  : "bg-white text-gray-800 rounded-bl-sm shadow-sm border border-gray-100"
                              }`}>
                                <p>{msg.message}</p>
                              </div>
                              {isMine && hoveredMsgId === msg.id && (
                                <button
                                  onClick={() => doDelete(msg.id)}
                                  className="w-6 h-6 rounded-full bg-gray-100 hover:bg-red-100 flex items-center justify-center transition-colors mb-1 flex-shrink-0"
                                  title="Delete message"
                                >
                                  <Trash2 size={11} className="text-gray-400 hover:text-red-500" />
                                </button>
                              )}
                            </div>
                            <p className={`text-[10px] mt-1 px-1 ${isMine ? "text-gray-400" : "text-gray-300"}`}>
                              {new Date(msg.createdAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
                            </p>
                          </div>
                          {isMine && (
                            <div className="w-7 h-7 rounded-full bg-emerald-800 flex items-center justify-center text-white text-xs font-bold flex-shrink-0 mb-5">
                              {user?.name?.charAt(0) ?? "P"}
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))
            )}
            <div ref={bottomRef} />
          </div>

          {/* Input area */}
          <div className="border-t border-gray-100 bg-white p-4">
            <form onSubmit={handleSend} className="flex gap-2">
              <Input
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder={proctorId ? "Type a message… (Enter to send)" : "No proctor assigned yet"}
                className="flex-1 bg-gray-50 border-gray-100 rounded-xl text-sm"
                autoComplete="off"
                disabled={proctorId === null}
              />
              <Button
                type="submit"
                className="bg-emerald-800 hover:bg-emerald-700 rounded-xl w-11 h-10 p-0 flex-shrink-0"
                disabled={isPending || !message.trim() || proctorId === null}
              >
                {isPending ? (
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <Send size={15} />
                )}
              </Button>
            </form>
            <p className="text-[10px] text-gray-300 mt-2 text-center">Hover over your own messages to delete them</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function ParentChat() {
  return (
    <RequireAuth allowedRoles={["parent"]}>
      <PortalLayout theme="parent">
        <ChatContent />
      </PortalLayout>
    </RequireAuth>
  );
}

import { Switch, Route, Router as WouterRouter } from "wouter";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { AuthProvider } from "@/contexts/AuthContext";
import { TenantProvider } from "@/contexts/TenantContext";
import NotFound from "@/pages/not-found";
import Landing from "@/pages/Landing";
import Login from "@/pages/Login";
import StudentDashboard from "@/pages/student/Dashboard";
import StudentAcademics from "@/pages/student/Academics";
import StudentScholarship from "@/pages/student/Scholarship";
import StudentGrievance from "@/pages/student/Grievance";
import StudentTimetable from "@/pages/student/Timetable";
import StudentNotes from "@/pages/student/Notes";
import ParentDashboard from "@/pages/parent/Dashboard";
import ParentChat from "@/pages/parent/Chat";
import FacultyDashboard from "@/pages/faculty/Dashboard";
import FacultyStudents from "@/pages/faculty/Students";
import FacultyAcademics from "@/pages/faculty/Academics";
import FacultyNotes from "@/pages/faculty/Notes";
import FacultyTimetable from "@/pages/faculty/Timetable";
import FacultyAttendance from "@/pages/faculty/Attendance";
import FacultyChat from "@/pages/faculty/Chat";
import FacultyAlertCenter from "@/pages/faculty/AlertCenter";
import AdminDashboard from "@/pages/admin/Dashboard";
import AdminUsers from "@/pages/admin/Users";
import AdminDemo from "@/pages/admin/Demo";
import AdminSettings from "@/pages/admin/Settings";

const queryClient = new QueryClient({
  defaultOptions: {
    queries: { refetchOnWindowFocus: false, retry: 1 },
  },
});

function Router() {
  return (
    <Switch>
      <Route path="/" component={Landing} />
      <Route path="/login" component={Login} />
      <Route path="/student" component={StudentDashboard} />
      <Route path="/student/academics" component={StudentAcademics} />
      <Route path="/student/scholarship" component={StudentScholarship} />
      <Route path="/student/grievance" component={StudentGrievance} />
      <Route path="/student/timetable" component={StudentTimetable} />
      <Route path="/student/notes" component={StudentNotes} />
      <Route path="/parent" component={ParentDashboard} />
      <Route path="/parent/chat" component={ParentChat} />
      <Route path="/faculty" component={FacultyDashboard} />
      <Route path="/faculty/students" component={FacultyStudents} />
      <Route path="/faculty/academics" component={FacultyAcademics} />
      <Route path="/faculty/attendance" component={FacultyAttendance} />
      <Route path="/faculty/notes" component={FacultyNotes} />
      <Route path="/faculty/timetable" component={FacultyTimetable} />
      <Route path="/faculty/chat" component={FacultyChat} />
      <Route path="/faculty/alerts" component={FacultyAlertCenter} />
      <Route path="/guardian-admin" component={AdminDashboard} />
      <Route path="/guardian-admin/users" component={AdminUsers} />
      <Route path="/guardian-admin/demo" component={AdminDemo} />
      <Route path="/guardian-admin/settings" component={AdminSettings} />
      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TenantProvider>
        <TooltipProvider>
          <WouterRouter base={import.meta.env.BASE_URL.replace(/\/$/, "")}>
            <AuthProvider>
              <Router />
            </AuthProvider>
          </WouterRouter>
          <Toaster />
        </TooltipProvider>
      </TenantProvider>
    </QueryClientProvider>
  );
}

export default App;

