import { useState, useEffect } from "react";
import { RequireAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";
import { Settings, Phone, Plus, Trash2, Info, CheckCircle2, AlertTriangle } from "lucide-react";

function AdminSettingsContent() {
  const { toast } = useToast();
  const [phones, setPhones] = useState<string[]>([]);
  const [newPhone, setNewPhone] = useState("");
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    fetch("/api/admin/settings", { credentials: "include" })
      .then(r => r.ok ? r.json() : {})
      .then((data: Record<string, string>) => {
        try {
          const parsed = JSON.parse(data["alert_redirect_phones"] ?? "[]");
          setPhones(Array.isArray(parsed) ? parsed : []);
        } catch {
          setPhones([]);
        }
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  async function savePhones(updated: string[]) {
    setSaving(true);
    try {
      const r = await fetch("/api/admin/settings", {
        method: "PUT",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ alert_redirect_phones: JSON.stringify(updated) }),
      });
      if (!r.ok) throw new Error("Failed to save");
      toast({ title: "Saved", description: "Demo phone list updated." });
    } catch {
      toast({ title: "Error", description: "Could not save settings.", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  }

  function addPhone() {
    const num = newPhone.trim().replace(/\s/g, "");
    if (!num) return;
    if (phones.includes(num)) {
      toast({ title: "Already in list", description: `${num} is already added.`, variant: "destructive" });
      return;
    }
    const updated = [...phones, num];
    setPhones(updated);
    setNewPhone("");
    savePhones(updated);
  }

  function removePhone(phone: string) {
    const updated = phones.filter(p => p !== phone);
    setPhones(updated);
    savePhones(updated);
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === "Enter") { e.preventDefault(); addPhone(); }
  }

  return (
    <div className="min-h-screen">
      <div className="page-header-admin px-8 pt-8 pb-14">
        <div className="max-w-7xl mx-auto">
          <h1 className="text-3xl font-bold text-white mb-1 flex items-center gap-2">
            <Settings size={26} /> System Settings
          </h1>
          <p className="text-violet-200/70 text-sm">Configure global system behaviour for all portals</p>
        </div>
      </div>

      <div className="max-w-3xl mx-auto px-8 -mt-6 pb-10 space-y-6">

        {/* Alert phone list */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
          <div className="flex items-center gap-2 mb-1">
            <Phone size={16} className="text-violet-600" />
            <h2 className="font-bold text-gray-900">Demo Alert Phone Numbers</h2>
          </div>
          <p className="text-xs text-gray-400 mb-4">
            These numbers appear as a dropdown in the Faculty Alert Center. During demos, faculty pick one of these to receive test calls/WhatsApp instead of the student's real number.
          </p>

          {/* Twilio trial warning */}
          <div className="bg-amber-50 border border-amber-100 rounded-xl p-4 mb-5 flex gap-3">
            <AlertTriangle size={15} className="text-amber-600 flex-shrink-0 mt-0.5" />
            <div className="text-xs text-amber-800 leading-relaxed">
              <strong>Twilio Trial Accounts:</strong> You can only call/WhatsApp numbers that are verified in your Twilio console.
              To verify a number: go to <strong>Twilio Console → Verified Caller IDs → Add a new Caller ID</strong> and follow the steps.
              Once verified, add that number here and it will work instantly.
              <br /><br />
              <strong>Format:</strong> Indian numbers like <code className="bg-amber-100 px-1 rounded">9380838591</code> (no country code) or with code: <code className="bg-amber-100 px-1 rounded">+919380838591</code>.
            </div>
          </div>

          {/* Add new phone */}
          <div className="flex gap-2 mb-4">
            <Input
              value={newPhone}
              onChange={e => setNewPhone(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="e.g. 9380838591 or +919380838591"
              className="flex-1 font-mono text-sm"
              disabled={saving}
            />
            <Button
              onClick={addPhone}
              disabled={saving || !newPhone.trim()}
              className="bg-violet-700 hover:bg-violet-800 text-white gap-1.5 flex-shrink-0"
            >
              <Plus size={14} /> Add
            </Button>
          </div>

          {/* Phone list */}
          {loading ? (
            <div className="space-y-2">
              {[1, 2].map(i => <div key={i} className="h-10 bg-gray-100 rounded-xl animate-pulse" />)}
            </div>
          ) : phones.length === 0 ? (
            <div className="border border-dashed border-gray-200 rounded-xl p-6 text-center">
              <Phone size={24} className="text-gray-200 mx-auto mb-2" />
              <p className="text-xs text-gray-400">No demo phones added yet.</p>
              <p className="text-xs text-gray-300 mt-1">The Alert Center will use each student's own number.</p>
            </div>
          ) : (
            <div className="space-y-2">
              {phones.map((phone, i) => (
                <div key={phone} className="flex items-center gap-3 bg-gray-50 rounded-xl px-4 py-3 group">
                  <div className="w-6 h-6 rounded-full bg-violet-100 text-violet-700 flex items-center justify-center text-[10px] font-bold flex-shrink-0">
                    {i + 1}
                  </div>
                  <code className="flex-1 text-sm text-gray-800 font-mono">{phone}</code>
                  <div className="flex items-center gap-2">
                    <CheckCircle2 size={13} className="text-emerald-400" />
                    <span className="text-[10px] text-gray-400">In dropdown</span>
                    <button
                      onClick={() => removePhone(phone)}
                      className="w-7 h-7 rounded-lg bg-transparent hover:bg-red-100 flex items-center justify-center ml-1 transition-colors"
                      title="Remove"
                      disabled={saving}
                    >
                      <Trash2 size={13} className="text-gray-300 hover:text-red-500" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Published data info */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
          <div className="flex items-center gap-2 mb-3">
            <Info size={15} className="text-violet-500" />
            <h2 className="font-bold text-gray-900 text-sm">Will demo data stay after publishing?</h2>
          </div>
          <div className="space-y-3 text-xs text-gray-600 leading-relaxed">
            <div className="bg-emerald-50 border border-emerald-100 rounded-xl p-3 text-emerald-800">
              <strong>Yes — your current data stays intact</strong> when you publish. Publishing deploys your code but the production database is the same one you're using now. Nothing is wiped.
            </div>
            <div className="flex gap-2.5">
              <div className="w-5 h-5 rounded-full bg-violet-100 text-violet-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0 mt-0.5">!</div>
              <div>If you ever accidentally wipe data in production, use <strong>Admin → Demo Controls → Restore Demo Data</strong> to re-seed everything from scratch (all 4 at-risk students, faculty, parents, messages, etc.).</div>
            </div>
            <div className="flex gap-2.5">
              <div className="w-5 h-5 rounded-full bg-violet-100 text-violet-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0 mt-0.5">!</div>
              <div>To edit users (name, phone, email, password) after publishing: <strong>Admin → User Management</strong> — no database access needed.</div>
            </div>
            <div className="flex gap-2.5">
              <div className="w-5 h-5 rounded-full bg-violet-100 text-violet-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0 mt-0.5">!</div>
              <div>To run raw SQL on the production database: go to Replit → your project → <strong>Tools → Database</strong> → Query tab. Runs against the live database.</div>
            </div>
          </div>
        </div>

        {/* How to manage data */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
          <h2 className="font-bold text-gray-900 mb-3 text-sm">Quick Reference — Managing Data After Publishing</h2>
          <div className="overflow-hidden rounded-xl border border-gray-100">
            <table className="w-full text-xs">
              <thead>
                <tr className="bg-gray-50 border-b border-gray-100">
                  <th className="text-left text-gray-400 font-semibold uppercase tracking-wider px-4 py-2.5">Task</th>
                  <th className="text-left text-gray-400 font-semibold uppercase tracking-wider px-4 py-2.5">How</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {[
                  ["Edit user name/phone/email", "Admin → User Management → pencil icon"],
                  ["Reset a user's password", "Admin → User Management → reset password"],
                  ["Add/remove demo phones", "Admin → System Settings (this page)"],
                  ["Restore all demo data", "Admin → Demo Controls → Restore Demo Data"],
                  ["Run a SQL query", "Replit → Tools → Database → Query tab"],
                  ["Add a new DB column", "Edit schema file → Shell: pnpm --filter @workspace/db run push"],
                ].map(([task, how], i) => (
                  <tr key={i} className="hover:bg-gray-50/60">
                    <td className="px-4 py-3 font-medium text-gray-700">{task}</td>
                    <td className="px-4 py-3 text-gray-400 font-mono">{how}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

      </div>
    </div>
  );
}

export default function AdminSettings() {
  return (
    <RequireAuth allowedRoles={["admin"]}>
      <PortalLayout theme="admin">
        <AdminSettingsContent />
      </PortalLayout>
    </RequireAuth>
  );
}

