import { useState } from "react";
import { RequireAuth } from "@/contexts/AuthContext";
import { PortalLayout } from "@/components/PortalLayout";
import { useQuery } from "@tanstack/react-query";
import {
  AlertTriangle, Phone, MessageCircle, CheckCircle2, XCircle,
  Loader2, PhoneCall, ChevronDown, ChevronUp, Zap,
  CheckSquare, Square, Settings
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";

interface AtRiskStudent {
  id: number;
  name: string;
  usn: string | null;
  section: string | null;
  branch: string | null;
  phone: string | null;
  semester: number | null;
  avgAttendance: number;
  avgCiePct: number;
  avgCie: number;
  lowAttendance: boolean;
  lowMarks: boolean;
  parent: { id: number; name: string; phone: string | null } | null;
}

type AlertStatus = "idle" | "loading" | "success" | "error";

async function fetchAtRisk(): Promise<AtRiskStudent[]> {
  const r = await fetch("/api/alerts/at-risk", { credentials: "include" });
  if (!r.ok) throw new Error("Failed to fetch at-risk students");
  return r.json();
}

async function fetchDemoPhones(): Promise<string[]> {
  const r = await fetch("/api/admin/settings", { credentials: "include" });
  if (!r.ok) return [];
  const data = await r.json();
  try {
    const parsed = JSON.parse(data["alert_redirect_phones"] ?? "[]");
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

// ── Phone picker row ─────────────────────────────────────────────────────────
function PhonePicker({
  label,
  value,
  onChange,
  demoPhones,
  disabled,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  demoPhones: string[];
  disabled?: boolean;
}) {
  const [open, setOpen] = useState(false);

  return (
    <div className="relative">
      <label className="text-[10px] text-gray-400 font-semibold uppercase tracking-wider">{label}</label>
      <div className="flex gap-1 mt-1">
        <Input
          value={value}
          onChange={e => onChange(e.target.value)}
          placeholder="9XXXXXXXXX"
          className="flex-1 text-xs h-8 font-mono"
          disabled={disabled}
        />
        {demoPhones.length > 0 && !disabled && (
          <div className="relative">
            <button
              type="button"
              onClick={() => setOpen(v => !v)}
              className="h-8 px-2 rounded-md border border-input bg-white hover:bg-gray-50 flex items-center gap-0.5 text-gray-500 hover:text-gray-700 transition-colors"
              title="Pick a demo number"
            >
              <Phone size={11} />
              <ChevronDown size={10} />
            </button>
            {open && (
              <div className="absolute right-0 top-9 z-20 bg-white border border-gray-100 rounded-xl shadow-lg min-w-[160px] overflow-hidden">
                <div className="px-3 py-1.5 text-[9px] text-gray-400 font-semibold uppercase tracking-wider border-b border-gray-50">
                  Demo numbers
                </div>
                {demoPhones.map(ph => (
                  <button
                    key={ph}
                    type="button"
                    onClick={() => { onChange(ph); setOpen(false); }}
                    className="w-full text-left px-3 py-2 text-xs font-mono text-gray-700 hover:bg-violet-50 hover:text-violet-700 transition-colors"
                  >
                    {ph}
                  </button>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Single-student card ──────────────────────────────────────────────────────
function StudentAlertCard({
  student,
  selected,
  onToggle,
  demoPhones,
}: {
  student: AtRiskStudent;
  selected: boolean;
  onToggle: () => void;
  demoPhones: string[];
}) {
  const { toast } = useToast();
  const defaultPhone = demoPhones[0] ?? (student.phone ?? "");
  const defaultParent = demoPhones[0] ?? (student.parent?.phone ?? "");
  const [studentPhone, setStudentPhone] = useState(defaultPhone);
  const [parentPhone, setParentPhone] = useState(defaultParent);
  const [showPhones, setShowPhones] = useState(demoPhones.length === 0 && !student.phone);
  const [callStatus, setCallStatus] = useState<{ student: AlertStatus; parent: AlertStatus }>({ student: "idle", parent: "idle" });
  const [waStatus, setWaStatus] = useState<{ student: AlertStatus; parent: AlertStatus }>({ student: "idle", parent: "idle" });

  async function triggerCall(target: "student" | "parent") {
    const phone = target === "student" ? studentPhone : parentPhone;
    if (!phone) { toast({ title: "Phone required", description: `Pick or enter a ${target} phone number first`, variant: "destructive" }); return; }
    setCallStatus(s => ({ ...s, [target]: "loading" }));
    try {
      const r = await fetch("/api/alerts/call", {
        method: "POST", credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ studentId: student.id, phone }),
      });
      const data = await r.json();
      if (!r.ok) throw new Error(data.error);
      setCallStatus(s => ({ ...s, [target]: "success" }));
      toast({ title: "📞 Calling now!", description: data.message });
    } catch (err: any) {
      setCallStatus(s => ({ ...s, [target]: "error" }));
      toast({ title: "Call failed", description: err.message, variant: "destructive" });
    }
  }

  async function triggerWA(target: "student" | "parent") {
    const phone = target === "student" ? studentPhone : parentPhone;
    const parentName = target === "parent" ? (student.parent?.name ?? "Parent") : student.name;
    if (!phone) { toast({ title: "Phone required", description: `Pick or enter a ${target} WhatsApp number first`, variant: "destructive" }); return; }
    setWaStatus(s => ({ ...s, [target]: "loading" }));
    try {
      const r = await fetch("/api/alerts/whatsapp", {
        method: "POST", credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ studentId: student.id, phone, parentName, attendance: student.avgAttendance, avgMarks: student.avgCiePct }),
      });
      const data = await r.json();
      if (!r.ok) throw new Error(data.error);
      setWaStatus(s => ({ ...s, [target]: "success" }));
      toast({ title: "💬 WhatsApp sent!", description: data.message });
    } catch (err: any) {
      setWaStatus(s => ({ ...s, [target]: "error" }));
      toast({ title: "WhatsApp failed", description: err.message, variant: "destructive" });
    }
  }

  const icon = (s: AlertStatus) => {
    if (s === "loading") return <Loader2 size={12} className="animate-spin" />;
    if (s === "success") return <CheckCircle2 size={12} className="text-emerald-500" />;
    if (s === "error") return <XCircle size={12} className="text-red-500" />;
    return null;
  };

  const riskColor = student.lowAttendance && student.lowMarks ? "bg-red-50 border-red-100" : "bg-amber-50 border-amber-100";
  const badgeColor = student.lowAttendance && student.lowMarks ? "bg-red-100 text-red-700" : "bg-amber-100 text-amber-700";

  return (
    <div className={`bg-white border rounded-2xl overflow-hidden shadow-sm ${selected ? "ring-2 ring-rose-400" : ""}`}>
      {/* Header */}
      <div className={`px-5 py-3.5 flex items-center gap-3 border-b ${riskColor}`}>
        <button onClick={onToggle} className="flex-shrink-0">
          {selected ? <CheckSquare size={18} className="text-rose-600" /> : <Square size={18} className="text-gray-300" />}
        </button>
        <div className={`w-9 h-9 rounded-xl flex items-center justify-center font-bold text-sm flex-shrink-0 ${badgeColor}`}>
          {student.name.charAt(0)}
        </div>
        <div className="flex-1 min-w-0">
          <div className="font-bold text-gray-900 text-sm">{student.name}</div>
          <div className="text-xs text-gray-400">{student.usn} · Sem {student.semester} · {student.section}</div>
        </div>
        <div className="flex gap-2 flex-wrap justify-end">
          {student.lowAttendance && (
            <span className="text-[10px] bg-red-100 text-red-700 px-2 py-0.5 rounded-full font-bold">Att: {student.avgAttendance}%</span>
          )}
          {student.lowMarks && (
            <span className="text-[10px] bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full font-bold">CIE: {student.avgCie.toFixed(1)}/20</span>
          )}
        </div>
      </div>

      {/* Phone pickers */}
      <div className="px-5 py-3 border-b border-gray-50">
        <button
          className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-gray-600"
          onClick={() => setShowPhones(v => !v)}
        >
          <Phone size={11} /> Phone Numbers
          {demoPhones.length > 0 && (
            <span className="ml-1 text-[9px] bg-violet-100 text-violet-600 px-1.5 py-0.5 rounded-full font-semibold">
              {demoPhones.length} demo
            </span>
          )}
          {showPhones ? <ChevronUp size={11} /> : <ChevronDown size={11} />}
        </button>
        {showPhones && (
          <div className="grid grid-cols-2 gap-3 mt-2">
            <PhonePicker
              label="Student"
              value={studentPhone}
              onChange={setStudentPhone}
              demoPhones={demoPhones}
            />
            <PhonePicker
              label={`Parent${student.parent ? ` (${student.parent.name})` : " (none linked)"}`}
              value={parentPhone}
              onChange={setParentPhone}
              demoPhones={demoPhones}
              disabled={!student.parent}
            />
          </div>
        )}
        {!showPhones && demoPhones.length > 0 && (
          <div className="mt-1.5 flex items-center gap-1.5 text-[10px] text-violet-500">
            <Phone size={9} />
            <span className="font-mono">{studentPhone || "—"}</span>
            <span className="text-gray-300 mx-1">·</span>
            <span className="text-gray-400">Parent:</span>
            <span className="font-mono">{parentPhone || "—"}</span>
          </div>
        )}
      </div>

      {/* Action buttons */}
      <div className="px-5 py-3 grid grid-cols-2 gap-4">
        <div className="space-y-1.5">
          <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">Alert Student</div>
          <Button size="sm" variant="outline" className="w-full text-xs gap-1.5 h-8" onClick={() => triggerCall("student")} disabled={callStatus.student === "loading"}>
            <PhoneCall size={11} /> {callStatus.student === "loading" ? "Calling…" : "Voice Call"} {icon(callStatus.student)}
          </Button>
          <Button size="sm" variant="outline" className="w-full text-xs gap-1.5 h-8" onClick={() => triggerWA("student")} disabled={waStatus.student === "loading"}>
            <MessageCircle size={11} /> {waStatus.student === "loading" ? "Sending…" : "WhatsApp"} {icon(waStatus.student)}
          </Button>
        </div>
        <div className="space-y-1.5">
          <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">
            Alert Parent {!student.parent && <span className="text-red-400">(none linked)</span>}
          </div>
          <Button size="sm" variant="outline" className="w-full text-xs gap-1.5 h-8" onClick={() => triggerCall("parent")} disabled={callStatus.parent === "loading" || !student.parent}>
            <PhoneCall size={11} /> {callStatus.parent === "loading" ? "Calling…" : "Voice Call"} {icon(callStatus.parent)}
          </Button>
          <Button size="sm" variant="outline" className="w-full text-xs gap-1.5 h-8" onClick={() => triggerWA("parent")} disabled={waStatus.parent === "loading" || !student.parent}>
            <MessageCircle size={11} /> {waStatus.parent === "loading" ? "Sending…" : "WhatsApp"} {icon(waStatus.parent)}
          </Button>
        </div>
      </div>
    </div>
  );
}

// ── Bulk bar ─────────────────────────────────────────────────────────────────
function BulkActionBar({
  students,
  selected,
  phones,
  onClear,
}: {
  students: AtRiskStudent[];
  selected: Set<number>;
  phones: Record<number, { student: string; parent: string }>;
  onClear: () => void;
}) {
  const { toast } = useToast();
  const [bulkCallStatus, setBulkCallStatus] = useState<AlertStatus>("idle");
  const [bulkWAStatus, setBulkWAStatus] = useState<AlertStatus>("idle");
  const [progress, setProgress] = useState("");

  const selectedStudents = students.filter(s => selected.has(s.id));

  async function bulkCall() {
    const targets: { studentId: number; phone: string; label: string }[] = [];
    for (const s of selectedStudents) {
      const ph = phones[s.id];
      if (ph?.student) targets.push({ studentId: s.id, phone: ph.student, label: `${s.name} (student)` });
      if (ph?.parent && s.parent) targets.push({ studentId: s.id, phone: ph.parent, label: `${s.name} (parent: ${s.parent.name})` });
    }
    if (!targets.length) { toast({ title: "No phone numbers", description: "Open student cards and pick or enter phone numbers first", variant: "destructive" }); return; }
    setBulkCallStatus("loading");
    setProgress(`Calling ${targets.length} number${targets.length !== 1 ? "s" : ""}…`);
    try {
      const r = await fetch("/api/alerts/call/bulk", {
        method: "POST", credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ targets }),
      });
      const data = await r.json();
      setBulkCallStatus(data.failures.length === 0 ? "success" : "error");
      setProgress(`✓ ${data.successes.length} calls initiated${data.failures.length ? `, ${data.failures.length} failed` : ""}`);
      toast({ title: `📞 ${data.successes.length} calls initiated!`, description: data.failures.length ? `${data.failures.length} failed` : "All calls sent" });
    } catch (err: any) {
      setBulkCallStatus("error");
      setProgress("Bulk call failed");
      toast({ title: "Bulk call failed", description: err.message, variant: "destructive" });
    }
  }

  async function bulkWA() {
    const targets: { studentId: number; phone: string; parentName?: string; attendance?: number; avgMarks?: number; label: string }[] = [];
    for (const s of selectedStudents) {
      const ph = phones[s.id];
      if (ph?.student) targets.push({ studentId: s.id, phone: ph.student, parentName: s.name, attendance: s.avgAttendance, avgMarks: s.avgCiePct, label: `${s.name} (student)` });
      if (ph?.parent && s.parent) targets.push({ studentId: s.id, phone: ph.parent, parentName: s.parent.name, attendance: s.avgAttendance, avgMarks: s.avgCiePct, label: `${s.name} (parent: ${s.parent.name})` });
    }
    if (!targets.length) { toast({ title: "No phone numbers", description: "Open student cards and pick or enter phone numbers first", variant: "destructive" }); return; }
    setBulkWAStatus("loading");
    setProgress(`Sending ${targets.length} WhatsApp message${targets.length !== 1 ? "s" : ""}…`);
    try {
      const r = await fetch("/api/alerts/whatsapp/bulk", {
        method: "POST", credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ targets }),
      });
      const data = await r.json();
      setBulkWAStatus(data.failures.length === 0 ? "success" : "error");
      setProgress(`✓ ${data.successes.length} WhatsApps sent${data.failures.length ? `, ${data.failures.length} failed` : ""}`);
      toast({ title: `💬 ${data.successes.length} WhatsApps sent!`, description: data.failures.length ? `${data.failures.length} failed` : "All messages sent" });
    } catch (err: any) {
      setBulkWAStatus("error");
      setProgress("Bulk WhatsApp failed");
      toast({ title: "Bulk WhatsApp failed", description: err.message, variant: "destructive" });
    }
  }

  return (
    <div className="sticky top-4 z-10 bg-rose-900 text-white rounded-2xl px-5 py-4 flex items-center gap-4 shadow-lg mb-6">
      <div className="flex items-center gap-2 flex-1">
        <div className="w-8 h-8 rounded-full bg-white/20 flex items-center justify-center font-bold text-sm">{selected.size}</div>
        <div>
          <div className="font-bold text-sm">{selected.size} student{selected.size !== 1 ? "s" : ""} selected</div>
          {progress && <div className="text-xs text-rose-200">{progress}</div>}
        </div>
      </div>
      <Button size="sm" className="bg-white/20 hover:bg-white/30 text-white gap-1.5 text-xs border-0" onClick={bulkCall} disabled={bulkCallStatus === "loading"}>
        {bulkCallStatus === "loading" ? <Loader2 size={13} className="animate-spin" /> : <PhoneCall size={13} />}
        Call All
        {bulkCallStatus === "success" && <CheckCircle2 size={13} className="text-emerald-300" />}
      </Button>
      <Button size="sm" className="bg-white/20 hover:bg-white/30 text-white gap-1.5 text-xs border-0" onClick={bulkWA} disabled={bulkWAStatus === "loading"}>
        {bulkWAStatus === "loading" ? <Loader2 size={13} className="animate-spin" /> : <MessageCircle size={13} />}
        WhatsApp All
        {bulkWAStatus === "success" && <CheckCircle2 size={13} className="text-emerald-300" />}
      </Button>
      <button onClick={onClear} className="text-rose-300 hover:text-white text-xs underline">Clear</button>
    </div>
  );
}

// ── Main page ────────────────────────────────────────────────────────────────
function AlertCenterContent() {
  const { data: atRisk = [], isLoading } = useQuery({
    queryKey: ["at-risk-students"],
    queryFn: fetchAtRisk,
    refetchInterval: 30000,
  });

  const { data: demoPhones = [] } = useQuery({
    queryKey: ["demo-phones"],
    queryFn: fetchDemoPhones,
    staleTime: 60000,
  });

  const [selected, setSelected] = useState<Set<number>>(new Set());
  const [phones] = useState<Record<number, { student: string; parent: string }>>(() => ({}));

  atRisk.forEach(s => {
    if (!phones[s.id]) {
      phones[s.id] = {
        student: demoPhones[0] ?? (s.phone ?? ""),
        parent: demoPhones[0] ?? (s.parent?.phone ?? ""),
      };
    }
  });

  function toggleSelect(id: number) {
    setSelected(prev => { const next = new Set(prev); next.has(id) ? next.delete(id) : next.add(id); return next; });
  }

  function selectAll() { setSelected(new Set(atRisk.map(s => s.id))); }
  function clearAll() { setSelected(new Set()); }

  return (
    <div className="min-h-screen">
      <div className="page-header-faculty px-8 pt-8 pb-14">
        <div className="max-w-5xl mx-auto">
          <p className="text-rose-300 text-xs font-semibold uppercase tracking-wider mb-2">Dropout Prevention</p>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <PhoneCall size={22} /> Alert Center
          </h1>
          <p className="text-rose-200/70 text-sm mt-1">
            Students with attendance &lt; 75% or CIE avg &lt; 60% — call &amp; WhatsApp them individually or in bulk
          </p>
        </div>
      </div>

      <div className="max-w-5xl mx-auto px-8 -mt-6 pb-12">
        {/* How it works */}
        <div className="bg-white border border-gray-100 rounded-2xl p-5 mb-5 shadow-sm">
          <div className="text-sm font-bold text-gray-700 mb-3 flex items-center gap-2">
            <Zap size={14} className="text-amber-500" /> How it works
          </div>
          <div className="grid grid-cols-3 gap-4 text-xs text-gray-500">
            <div className="flex gap-2.5">
              <div className="w-6 h-6 rounded-full bg-rose-100 text-rose-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0">1</div>
              <div><div className="font-semibold text-gray-700 mb-0.5">Voice Call (multilingual)</div>English message plays → Press 1 for ಕನ್ನಡ → Press 2 for हिंदी → Press 0 to repeat</div>
            </div>
            <div className="flex gap-2.5">
              <div className="w-6 h-6 rounded-full bg-emerald-100 text-emerald-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0">2</div>
              <div><div className="font-semibold text-gray-700 mb-0.5">WhatsApp (3 languages)</div>Sends EN + ಕನ್ನಡ + हिंदी with attendance %, CIE marks, and action required</div>
            </div>
            <div className="flex gap-2.5">
              <div className="w-6 h-6 rounded-full bg-blue-100 text-blue-700 flex items-center justify-center font-bold text-[10px] flex-shrink-0">3</div>
              <div><div className="font-semibold text-gray-700 mb-0.5">Bulk Mode</div>Tick students → "Call All" or "WhatsApp All" — sends to student + parent simultaneously</div>
            </div>
          </div>
        </div>

        {isLoading ? (
          <div className="grid grid-cols-1 gap-4">
            {[1, 2, 3].map(i => <div key={i} className="h-44 bg-gray-100 animate-pulse rounded-2xl" />)}
          </div>
        ) : atRisk.length === 0 ? (
          <div className="bg-white border border-gray-100 rounded-2xl p-16 text-center shadow-sm">
            <div className="w-16 h-16 rounded-2xl bg-emerald-50 flex items-center justify-center mx-auto mb-4">
              <CheckCircle2 size={28} className="text-emerald-400" />
            </div>
            <div className="font-bold text-gray-600 text-lg mb-2">All students on track!</div>
            <div className="text-gray-400 text-sm">No students have attendance below 75% or CIE marks below 60%</div>
          </div>
        ) : (
          <>
            {/* Top bar */}
            <div className="flex items-center gap-3 mb-4 flex-wrap">
              <div className="flex items-center gap-2 bg-red-100 text-red-700 text-xs font-bold px-3 py-1.5 rounded-full">
                <AlertTriangle size={12} /> {atRisk.length} student{atRisk.length !== 1 ? "s" : ""} need attention
              </div>
              <button
                onClick={selected.size === atRisk.length ? clearAll : selectAll}
                className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-gray-700 bg-white border border-gray-200 px-3 py-1.5 rounded-full"
              >
                {selected.size === atRisk.length ? <CheckSquare size={12} /> : <Square size={12} />}
                {selected.size === atRisk.length ? "Deselect All" : "Select All"}
              </button>
              {demoPhones.length > 0 && (
                <div className="flex items-center gap-1.5 text-[10px] bg-violet-50 text-violet-600 px-3 py-1.5 rounded-full">
                  <Phone size={10} /> {demoPhones.length} demo phone{demoPhones.length !== 1 ? "s" : ""} — click <Phone size={9} className="inline" /> on a card to pick
                </div>
              )}
              <div className="text-xs text-gray-400 ml-auto flex items-center gap-1.5">
                EN / ಕನ್ನಡ / हिंदी · Twilio
                <a href="/guardian-admin/settings" className="text-violet-400 hover:text-violet-600" title="Manage demo phones">
                  <Settings size={11} />
                </a>
              </div>
            </div>

            {selected.size > 0 && (
              <BulkActionBar students={atRisk} selected={selected} phones={phones} onClear={clearAll} />
            )}

            <div className="grid grid-cols-1 gap-4">
              {atRisk.map(s => (
                <StudentAlertCard
                  key={s.id}
                  student={s}
                  selected={selected.has(s.id)}
                  onToggle={() => toggleSelect(s.id)}
                  demoPhones={demoPhones}
                />
              ))}
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default function FacultyAlertCenter() {
  return (
    <RequireAuth allowedRoles={["faculty"]}>
      <PortalLayout theme="faculty">
        <AlertCenterContent />
      </PortalLayout>
    </RequireAuth>
  );
}

